SkillUtil = {}

function SkillUtil:readBook(player, hint, title)
    HostApi.sendContentTip(player.rakssid, hint, title)
end

function SkillUtil:useChristmasBoxItem(player, itemId)
    local data = {}
    data.index = ChristmasConfig.Type.UseType
    data.itemId = itemId
    GamePacketSender:sendChristUseBoxItem(player.rakssid, data)
    if itemId == Define.ChristmasBox.COMMON then
        if player.enableIndie then
            GameAnalytics:design(player.userId, 0, { "g1048common_click_indie", Define.ClickType.TYPE3})
        else
            GameAnalytics:design(player.userId, 0, { "g1048common_click", Define.ClickType.TYPE3})
        end
    end
    if itemId == Define.ChristmasBox.FINE then
        if player.enableIndie then
            GameAnalytics:design(player.userId, 0, { "g1048common_click_indie", Define.ClickType.TYPE4})
        else
            GameAnalytics:design(player.userId, 0, { "g1048common_click", Define.ClickType.TYPE4})
        end
    end
end


return SkillUtil